import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ArrowLeft, FileText, Upload, Calendar, User as UserIcon, DollarSign, Tag, X, CheckCircle2, Sparkles, Loader2, Edit2, Search, ChevronDown, Check, Trash2, Plus, AlertCircle } from 'lucide-react';
import { ViewState, DocStatus, DocType, UserRole, User } from '../types';
import { db } from '../utils/firebase';
import { collection, addDoc, getDocs, doc, updateDoc, increment, query } from 'firebase/firestore';
import { GoogleGenAI, Type } from "@google/genai";

interface UploadDocumentsProps {
  onBack: () => void;
  onNavigate: (view: ViewState) => void;
  currentUser: User;
}

interface QueuedDocument {
  id: string;
  file: File;
  status: 'pending' | 'analyzing' | 'success' | 'error';

  // Form Data
  title: string;
  selectedUserId: string;
  isManualEntry: boolean;
  manualName: string;
  manualEmail: string;
  docType: DocType;
  period: string;
  amount: string;

  // UI Helpers
  extractedFields: string[];
