            <button 
                onClick={() => onRemove(docItem.id)}
                className="absolute top-4 right-4 text-slate-400 hover:text-red-500 transition-colors p-1"
                title="Remove document"
            >
                <Trash2 size={18} />
            </button>

            <div className="flex items-start gap-4 mb-6 pr-8">
