              {/* Grid of Cards */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {queue.map((docItem) => (
                      <DocumentCard 
                        key={docItem.id} 
                        docItem={docItem} 
                        users={usersList}
                        areUsersLoading={areUsersLoading}
                        onUpdate={handleUpdate}
                        onRemove={handleRemove}
                      />
                  ))}
              </div>
          </div>
      )}
    </div>
  );
};

