rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is admin
    function isAdmin() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'Admin';
    }

    // User profiles
    match /users/{userId} {
      allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());

      match /documents/{docId} {
        allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());
      }
    }

    // Top-level concerns collection for easier Admin management
    match /concerns/{concernId} {
      allow create: if request.auth != null;
      // Admins read all, Users read their own
      allow read: if request.auth != null && (resource.data.employeeId == request.auth.uid || isAdmin());
      // Only Admins can update status (resolve)
      allow update: if request.auth != null && isAdmin();
    }

    // Audit logs
    match /audit_logs/{logId} {
      allow read: if request.auth != null && isAdmin();
      allow create: if request.auth != null;
    }
  }
}

import React, { useState, useEffect } from 'react';
import { MessageSquare, CheckCircle, Clock, Send, AlertCircle, AlertTriangle, User as UserIcon } from 'lucide-react';
import { User, UserRole, Concern } from '../types';
import { db } from '../utils/firebase';
import { collection, addDoc, getDocs, doc, updateDoc, query, where, orderBy } from 'firebase/firestore';

interface ConcernsProps {
  currentUser: User;
}

const Concerns: React.FC<ConcernsProps> = ({ currentUser }) => {
  const [concerns, setConcerns] = useState<Concern[]>([]);
  const [subject, setSubject] = useState('');
  const [message, setMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const [permissionError, setPermissionError] = useState(false);

  // Admin filter states
  const [filterStatus, setFilterStatus] = useState<'All' | 'Open' | 'Resolved'>('All');

  useEffect(() => {
    loadConcerns();
  }, [currentUser]);

  const loadConcerns = async () => {
    setPermissionError(false);
    try {
        let q;
        const concernsRef = collection(db, 'concerns');

        if (currentUser.role === UserRole.ADMIN) {
             // Admin: Fetch ALL concerns
             // We fetch all and sort client side to avoid complex index requirements on 'createdAt'
             q = query(concernsRef);
        } else {
             // Employee: Fetch ONLY their own concerns
             q = query(concernsRef, where('employeeId', '==', currentUser.id));
        }

        const snapshot = await getDocs(q);
        const loadedConcerns: Concern[] = [];

        snapshot.forEach(doc => {
            const data = doc.data();
            loadedConcerns.push({
                id: doc.id,
                employeeId: data.employeeId,
                employeeName: data.employeeName,
                subject: data.subject,
                message: data.message,
                status: data.status,
                createdAt: data.createdAt
            });
        });

        // Client-side sort by date descending (newest first)
        // This handles format "Jan 1, 2024, 10:00 AM" or ISO strings
        loadedConcerns.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
        setConcerns(loadedConcerns);
    } catch (error: any) {
        console.error("Error loading concerns:", error);
        if (error.code === 'permission-denied') {
            setPermissionError(true);
        }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg('');
    setSuccessMsg('');

    if (!subject.trim() || !message.trim()) {
      setErrorMsg('Please fill in both the subject and the message.');
      return;
    }

    setIsSubmitting(true);

    try {
      const newConcern = {
        employeeId: currentUser.id,
        employeeName: currentUser.name,
        subject: subject,
        message: message,
        status: 'Open' as const,
        createdAt: new Date().toLocaleString('en-US', { 
            month: 'short', 
            day: 'numeric', 
            year: 'numeric', 
            hour: '2-digit', 
            minute: '2-digit' 
        })
      };

      // Add to TOP-LEVEL concerns collection
      await addDoc(collection(db, 'concerns'), newConcern);

      await loadConcerns();

      setSubject('');
      setMessage('');
      setIsSubmitting(false);
      setSuccessMsg('Your concern has been submitted successfully.');

      // Clear success message after 5 seconds
      setTimeout(() => setSuccessMsg(''), 5000);
    } catch (error: any) {
        console.error("Error submitting concern:", error);
        if (error.code === 'permission-denied') {
            setErrorMsg("Permission denied. Please check Firestore rules.");
        } else {
            setErrorMsg("Failed to submit concern. Please try again.");
        }
        setIsSubmitting(false);
    }
  };

  const handleResolve = async (id: string) => {
    try {
        // Resolve in TOP-LEVEL collection
        const concernRef = doc(db, 'concerns', id);
        await updateDoc(concernRef, { status: 'Resolved' });

        // Optimistic update
        setConcerns(prev => prev.map(c => c.id === id ? { ...c, status: 'Resolved' as const } : c));
    } catch (error) {
        console.error("Error resolving concern:", error);
        alert("Failed to update ticket status. You may not have permission.");
    }
  };

  const displayedConcerns = concerns.filter(c => {
    if (filterStatus === 'All') return true;
    return c.status === filterStatus;
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-300 pb-20">
      {/* Header */}
      <div>
        <h2 className="text-2xl font-bold text-slate-900 dark:text-white tracking-tight">Support & Concerns</h2>
        <p className="text-slate-500 dark:text-slate-400">
          {currentUser.role === UserRole.ADMIN 
            ? 'Manage support tickets from all employees' 
            : 'Submit questions or report issues to the administrator'}
        </p>
      </div>

      {permissionError && (
          <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl p-4 flex items-center gap-3">
            <AlertTriangle className="text-red-600 dark:text-red-400 shrink-0" size={24} />
            <div>
                <h3 className="font-bold text-red-900 dark:text-red-200">Access Denied</h3>
                <p className="text-sm text-red-700 dark:text-red-300">
                    Your security rules need to be updated to support the new central database for concerns.
                    <br />
                    Please go to <strong>Manage Users</strong> to copy the new configuration.
                </p>
            </div>
          </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Employee Submission Form - Employees or Admin self-submit */}
        <div className="lg:col-span-1">
            <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 p-6 sticky top-6 transition-colors">
              <h3 className="font-bold text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                <MessageSquare size={20} className="text-blue-600 dark:text-blue-400" />
                Submit a Concern
              </h3>

              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">Subject</label>
                  <input 
                    type="text"
                    placeholder="Brief summary of the issue"
                    className="w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:outline-none focus:bg-white dark:focus:bg-slate-800 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 dark:focus:border-blue-400 transition-all text-sm text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500"
                    value={subject}
                    onChange={(e) => setSubject(e.target.value)}
                    disabled={isSubmitting}
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-1">Message</label>
                  <textarea 
                    placeholder="Describe your concern in detail..."
                    rows={6}
                    className="w-full px-4 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:outline-none focus:bg-white dark:focus:bg-slate-800 focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 dark:focus:border-blue-400 transition-all text-sm resize-none text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500"
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    disabled={isSubmitting}
                  />
                </div>

                {errorMsg && (
                  <div className="p-3 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-300 text-sm rounded-lg flex items-center gap-2 border border-red-100 dark:border-red-800">
                    <AlertCircle size={16} />
                    {errorMsg}
                  </div>
                )}

                {successMsg && (
                  <div className="p-3 bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-300 text-sm rounded-lg flex items-center gap-2 border border-green-100 dark:border-green-800">
                    <CheckCircle size={16} />
                    {successMsg}
                  </div>
                )}

                <button
                  type="submit"
                  disabled={isSubmitting}
                  className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl shadow-lg shadow-blue-200 dark:shadow-none transition-all transform active:scale-[0.98] flex items-center justify-center gap-2"
                >
                  {isSubmitting ? (
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  ) : (
                    <>
                      <Send size={18} />
                      Submit Concern
                    </>
                  )}
                </button>
              </form>
            </div>
          </div>

        {/* Concerns List */}
        <div className="lg:col-span-2">
          <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 flex flex-col h-full transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <h3 className="font-bold text-slate-900 dark:text-white">
                {currentUser.role === UserRole.ADMIN ? 'All Support Tickets' : 'My Ticket History'}
              </h3>

              <div className="flex gap-2">
                 {(['All', 'Open', 'Resolved'] as const).map(status => (
                   <button
                    key={status}
                    onClick={() => setFilterStatus(status)}
                    className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-colors ${
                      filterStatus === status 
                        ? 'bg-slate-900 dark:bg-slate-100 text-white dark:text-slate-900' 
                        : 'bg-slate-50 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700'
                    }`}
                   >
                     {status}
                   </button>
                 ))}
              </div>
            </div>

            <div className="p-6 space-y-4">
              {displayedConcerns.length === 0 ? (
                <div className="text-center py-12 text-slate-500 dark:text-slate-400 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-dashed border-slate-200 dark:border-slate-700">
                  <MessageSquare size={32} className="mx-auto mb-3 opacity-20" />
                  <p>No concerns found matching your filter.</p>
                </div>
              ) : (
                displayedConcerns.map(concern => (
                  <div key={concern.id} className={`p-5 rounded-xl border transition-all ${
                    concern.status === 'Open' 
                      ? 'bg-white dark:bg-slate-800 border-orange-100 dark:border-orange-900/30 shadow-[0_4px_20px_-10px_rgba(251,146,60,0.2)] dark:shadow-none' 
                      : 'bg-slate-50 dark:bg-slate-800/30 border-slate-100 dark:border-slate-800 opacity-75 hover:opacity-100'
                  }`}>
                    <div className="flex justify-between items-start gap-4">
                      <div className="space-y-1 w-full">
                        <div className="flex items-center gap-2">
                          <span className={`px-2 py-0.5 text-[10px] font-bold uppercase tracking-wider rounded-full ${
                            concern.status === 'Open' ? 'bg-orange-100 text-orange-700 dark:bg-orange-900/40 dark:text-orange-300' : 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-300'
                          }`}>
                            {concern.status}
                          </span>
                          <span className="text-xs text-slate-400 dark:text-slate-500 flex items-center gap-1">
                            <Clock size={12} />
                            {concern.createdAt}
                          </span>
                        </div>

                        {/* Always show employee name if available, helps context even for self */}
                        <div className="flex items-center gap-1.5 text-xs font-semibold text-blue-600 dark:text-blue-400 mt-1.5">
                            <UserIcon size={12} />
                            {concern.employeeName}
                        </div>

                        <h4 className="font-bold text-slate-900 dark:text-white text-lg mt-1">{concern.subject}</h4>
                        <p className="text-slate-600 dark:text-slate-300 text-sm mt-2 leading-relaxed bg-slate-50/50 dark:bg-slate-900/50 p-3 rounded-lg border border-slate-100/50 dark:border-slate-700/50 whitespace-pre-wrap">
                          {concern.message}
                        </p>
                      </div>

                      {concern.status === 'Open' && currentUser.role === UserRole.ADMIN && (
                        <button 
                          onClick={() => handleResolve(concern.id)}
                          className="shrink-0 flex items-center gap-1 bg-green-50 dark:bg-green-900/20 hover:bg-green-100 dark:hover:bg-green-900/30 text-green-700 dark:text-green-300 px-3 py-1.5 rounded-lg text-xs font-bold transition-colors border border-green-200 dark:border-green-800"
                        >
                          <CheckCircle size={14} />
                          <span className="hidden sm:inline">Resolve</span>
                          <span className="sm:hidden">✓</span>
                        </button>
                      )}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Concerns;

import React, { useState, useEffect } from 'react';
import { Search, Users, Shield, User as UserIcon, Calendar, FileText, RefreshCw, AlertTriangle, Activity, Clock, Copy, Check } from 'lucide-react';
import StatsCard from '../components/StatsCard';
import { UserRole, User, AuditLogEntry } from '../types';
import { db } from '../utils/firebase';
import { collection, getDocs, getDoc, doc, updateDoc, query, addDoc, orderBy, limit } from 'firebase/firestore';

interface ManageUsersProps {
  currentUser?: User;
}

const ManageUsers: React.FC<ManageUsersProps> = ({ currentUser }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [users, setUsers] = useState<User[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLogEntry[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [permissionError, setPermissionError] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    fetchUsers();
    fetchAuditLogs();
  }, [currentUser]);

  const fetchUsers = async () => {
    if (!currentUser) return;
    setIsLoading(true);
    setPermissionError(false);

    try {
      const loadedUsers: User[] = [];

      if (currentUser.role === UserRole.ADMIN) {
        // Admin: Fetch all users
        const usersRef = collection(db, 'users');
        const q = query(usersRef); 
        const querySnapshot = await getDocs(q);

        querySnapshot.forEach((doc) => {
          const data = doc.data();
          loadedUsers.push({
            id: doc.id,
            name: data.name || 'Unknown',
            email: data.email || '',
            role: data.role as UserRole,
            joinedAt: data.joinedAt || '',
            docCount: data.docCount || 0,
            avatarUrl: data.avatarUrl
          });
        });

        // Sort alphabetically by name
        loadedUsers.sort((a, b) => a.name.localeCompare(b.name));

      } else {
        // Normal User: Fetch own profile only using getDoc
        const userRef = doc(db, 'users', currentUser.id);
        const userSnap = await getDoc(userRef);

        if (userSnap.exists()) {
          const data = userSnap.data();
          loadedUsers.push({
            id: userSnap.id,
            name: data.name || 'Unknown',
            email: data.email || '',
            role: data.role as UserRole,
            joinedAt: data.joinedAt || '',
            docCount: data.docCount || 0,
            avatarUrl: data.avatarUrl
          });
        }
      }

      setUsers(loadedUsers);
    } catch (error: any) {
        if (error.code === 'permission-denied') {
            setPermissionError(true);
            // Do not console.error permission denied as it is handled by UI
        } else {
            console.error("Error fetching users:", error);
        }

        // Fallback: show current user if fetch failed but we have prop
        if (currentUser && users.length === 0) {
            setUsers([currentUser]);
        }
    } finally {
      setIsLoading(false);
    }
  };

  const fetchAuditLogs = async () => {
    if (!currentUser || currentUser.role !== UserRole.ADMIN) return;

    try {
      const logsRef = collection(db, 'audit_logs');
      // Fetch latest 20 logs
      const q = query(logsRef, orderBy('timestamp', 'desc'), limit(20));
      const querySnapshot = await getDocs(q);

      const loadedLogs: AuditLogEntry[] = [];
      querySnapshot.forEach((doc) => {
        const data = doc.data();
        loadedLogs.push({
          id: doc.id,
          action: data.action,
          executorId: data.executorId,
          executorName: data.executorName,
          targetUserId: data.targetUserId,
          targetUserName: data.targetUserName,
          details: data.details,
          timestamp: data.timestamp
        });
      });
      setAuditLogs(loadedLogs);
    } catch (error) {
      // Quietly fail or log warning if needed, but for audit logs we can be lenient
      // console.warn("Error fetching audit logs", error);
    }
  };

  const logAction = async (action: string, targetUser: User, details: string) => {
    if (!currentUser) return;

    try {
      const newLog: Omit<AuditLogEntry, 'id'> = {
        action,
        executorId: currentUser.id,
        executorName: currentUser.name,
        targetUserId: targetUser.id,
        targetUserName: targetUser.name,
        details,
        timestamp: new Date().toLocaleString()
      };

      await addDoc(collection(db, 'audit_logs'), newLog);

      // Update local state to show immediately
      const logWithId = { ...newLog, id: Math.random().toString(36) };
      setAuditLogs(prev => [logWithId, ...prev]);

    } catch (error) {
      console.error("Failed to write audit log", error);
    }
  };

  const toggleUserRole = async (targetUser: User) => {
    // Prevent changing your own role if you are the only admin, 
    // but for now, we just prevent changing your own role to avoid lockout in this UI.
    if (currentUser && targetUser.id === currentUser.id) {
      alert("You cannot change your own permission level.");
      return;
    }

    setProcessingId(targetUser.id);
    const newRole = targetUser.role === UserRole.ADMIN ? UserRole.EMPLOYEE : UserRole.ADMIN;

    try {
      const userRef = doc(db, 'users', targetUser.id);
      await updateDoc(userRef, {
        role: newRole
      });

      // Log the action
      await logAction(
        'ROLE_CHANGE', 
        targetUser, 
        `Changed role from ${targetUser.role} to ${newRole}`
      );

      // Optimistic update locally
      setUsers(prev => prev.map(u => u.id === targetUser.id ? { ...u, role: newRole } : u));
    } catch (error) {
      console.error("Error updating role:", error);
      alert("Failed to update user role. Check database permissions.");
    } finally {
      setProcessingId(null);
    }
  };

  const copyRulesToClipboard = () => {
    const rules = `rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is admin
    function isAdmin() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'Admin';
    }

    // User profiles
    match /users/{userId} {
      allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());

      match /documents/{docId} {
        allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());
      }
    }

    // Top-level concerns collection
    match /concerns/{concernId} {
      allow create: if request.auth != null;
      // Admins read all, Users read their own
      allow read: if request.auth != null && (resource.data.employeeId == request.auth.uid || isAdmin());
      // Admins can update (resolve)
      allow update: if request.auth != null && isAdmin();
    }

    // Audit logs
    match /audit_logs/{logId} {
      allow read: if request.auth != null && isAdmin();
      allow create: if request.auth != null;
    }
  }
}`;
    navigator.clipboard.writeText(rules);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const filteredUsers = users.filter(user => 
    user.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const totalUsers = users.length;
  const totalEmployees = users.filter(u => u.role === UserRole.EMPLOYEE).length;
  const totalAdmins = users.filter(u => u.role === UserRole.ADMIN).length;

  return (
    <div className="space-y-8 animate-in fade-in duration-300 pb-20">
      {/* Search Header */}
      <div className="bg-white dark:bg-slate-900 rounded-xl p-6 shadow-sm border border-slate-100 dark:border-slate-800 transition-colors">
        <div className="flex justify-between items-center mb-4">
             <h2 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Search size={20} />
                Search Users
            </h2>
            <div className="flex gap-2">
              <button 
                  onClick={() => { fetchUsers(); fetchAuditLogs(); }} 
                  disabled={isLoading}
                  className="p-2 text-slate-500 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-full transition-colors"
                  title="Refresh List"
              >
                  <RefreshCw size={18} className={isLoading ? 'animate-spin' : ''} />
              </button>
            </div>
        </div>

        <div className="relative">
            <input 
                type="text" 
                placeholder="Search by name or email..." 
                className="w-full pl-4 pr-4 py-3 border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-500"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatsCard 
          label="Total Users" 
          value={isLoading ? '-' : totalUsers} 
          icon={Users} 
          colorClass="bg-blue-50 text-blue-900 dark:bg-blue-900/20 dark:text-blue-100" 
          iconBgClass="bg-blue-600 text-white dark:bg-blue-500"
        />
        <StatsCard 
          label="Employees" 
          value={isLoading ? '-' : totalEmployees} 
          icon={UserIcon} 
          colorClass="bg-green-50 text-green-900 dark:bg-green-900/20 dark:text-green-100" 
          iconBgClass="bg-green-600 text-white dark:bg-green-500"
        />
        <StatsCard 
          label="Admins" 
          value={isLoading ? '-' : totalAdmins} 
          icon={Shield} 
          colorClass="bg-purple-50 text-purple-900 dark:bg-purple-900/20 dark:text-purple-100" 
          iconBgClass="bg-purple-600 text-white dark:bg-purple-500"
        />
      </div>

      {/* Users List */}
      <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 p-6 transition-colors">
        <h3 className="font-bold text-slate-900 dark:text-white mb-6">All Users</h3>

        {isLoading && users.length === 0 ? (
           <div className="text-center py-12 text-slate-400 dark:text-slate-500">Loading users...</div>
        ) : permissionError ? (
           <div className="bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800 rounded-xl p-6">
              <div className="text-center mb-4">
                  <AlertTriangle className="mx-auto text-orange-600 dark:text-orange-400 mb-2" size={32} />
                  <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2">Configuration Required</h3>
                  <p className="text-slate-600 dark:text-slate-300 mb-4 max-w-lg mx-auto">
                      Your Firestore Security Rules are blocking access. This is a security feature.
                      Please copy the rules below and paste them into your Firebase Console &gt; Firestore Database &gt; Rules.
                  </p>
              </div>

              <div className="bg-slate-900 rounded-lg p-4 relative group max-w-2xl mx-auto">
                <button 
                  onClick={copyRulesToClipboard}
                  className="absolute top-2 right-2 p-2 bg-slate-800 text-slate-400 hover:text-white rounded-md transition-colors"
                  title="Copy to clipboard"
                >
                  {copied ? <Check size={16} className="text-green-400" /> : <Copy size={16} />}
                </button>
                <pre className="text-xs text-slate-300 overflow-x-auto font-mono p-2">
{`rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is admin
    function isAdmin() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'Admin';
    }

    // User profiles
    match /users/{userId} {
      allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());

      match /documents/{docId} {
        allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());
      }
    }

    // Top-level concerns collection
    match /concerns/{concernId} {
      allow create: if request.auth != null;
      // Admins read all, Users read their own
      allow read: if request.auth != null && (resource.data.employeeId == request.auth.uid || isAdmin());
      // Admins can update (resolve)
      allow update: if request.auth != null && isAdmin();
    }

    // Audit logs
    match /audit_logs/{logId} {
      allow read: if request.auth != null && isAdmin();
      allow create: if request.auth != null;
    }
  }
}`}
                </pre>
              </div>
          </div>
        ) : (
        <div className="space-y-4">
            {filteredUsers.map(user => (
                <div key={user.id} className="flex flex-col lg:flex-row lg:items-center justify-between p-4 border border-slate-100 dark:border-slate-800 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors gap-4">
                    <div className="flex items-center gap-4 w-full lg:w-auto">
                        <div className="w-12 h-12 rounded-lg bg-slate-500 text-white flex items-center justify-center font-bold text-lg overflow-hidden shrink-0 ring-1 ring-slate-200 dark:ring-slate-700">
                             {user.avatarUrl ? (
                                <img src={user.avatarUrl} alt={user.name} className="w-full h-full object-cover" />
                             ) : (
                                user.name.charAt(0)
                             )}
                        </div>
                        <div className="min-w-0 flex-1">
                            <div className="flex flex-wrap items-center gap-2 mb-1">
                                <h4 className="font-bold text-slate-900 dark:text-slate-200 truncate">{user.name}</h4>
                                <span className={`text-[10px] px-2 py-0.5 rounded-full font-medium uppercase tracking-wide border ${
                                    user.role === UserRole.ADMIN 
                                    ? 'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-300 dark:border-purple-800' 
                                    : 'bg-green-100 text-green-700 border-green-200 dark:bg-green-900/30 dark:text-green-300 dark:border-green-800'
                                }`}>
                                    {user.role}
                                </span>
                            </div>
                            <p className="text-sm text-slate-500 dark:text-slate-400 truncate">
                                {user.email}
                            </p>
                        </div>
                    </div>

                    <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between lg:justify-end gap-4 lg:gap-6 text-sm text-slate-500 dark:text-slate-400 pl-16 lg:pl-0 w-full lg:w-auto">
                         <div className="flex items-center gap-4 sm:gap-6">
                             <div className="flex items-center gap-2" title="Date Joined">
                                 <Calendar size={16} />
                                 <span className="whitespace-nowrap">{user.joinedAt}</span>
                             </div>
                             <div className="flex items-center gap-2" title="Documents Count">
                                 <FileText size={16} />
                                 <span className="whitespace-nowrap">{user.docCount} docs</span>
                             </div>
                         </div>

                         {currentUser?.role === UserRole.ADMIN && (
                             <button 
                                onClick={() => toggleUserRole(user)}
                                disabled={processingId === user.id}
                                className={`w-full sm:w-auto px-4 py-2 rounded-lg font-bold text-xs transition-colors border shadow-sm flex items-center justify-center gap-2 ${
                                    user.role === UserRole.ADMIN
                                    ? 'bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 hover:text-red-600 hover:border-red-200'
                                    : 'bg-purple-600 text-white border-purple-600 hover:bg-purple-700'
                                }`}
                             >
                                {processingId === user.id ? (
                                    <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                                ) : (
                                    <Shield size={14} />
                                )}
                                {user.role === UserRole.ADMIN ? 'Revoke Admin' : 'Make Admin'}
                             </button>
                         )}
                    </div>
                </div>
            ))}

            {filteredUsers.length === 0 && (
                <div className="text-center py-12 text-slate-500 dark:text-slate-400">
                    No users found matching "{searchTerm}"
                </div>
            )}
        </div>
        )}
      </div>

      {/* Audit Log Section */}
      {currentUser?.role === UserRole.ADMIN && (
        <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 p-6 transition-colors">
            <h3 className="font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-2">
                <Activity size={20} className="text-orange-500" />
                Recent System Activity
            </h3>

            {auditLogs.length === 0 ? (
            <div className="text-center py-8 text-slate-400 dark:text-slate-500 text-sm italic">
                No recent administrative actions recorded.
            </div>
            ) : (
            <div className="space-y-4">
                {auditLogs.map(log => (
                <div key={log.id} className="flex items-start gap-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg border border-slate-100 dark:border-slate-800">
                    <div className={`mt-0.5 w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                        log.action === 'ROLE_CHANGE' 
                        ? 'bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400'
                        : 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400'
                    }`}>
                        {log.action === 'ROLE_CHANGE' ? <Shield size={14} /> : <Activity size={14} />}
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-sm font-semibold text-slate-800 dark:text-slate-200">
                        {log.executorName} <span className="text-slate-400 dark:text-slate-500 font-normal">modified</span> {log.targetUserName}
                        </p>
                        <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">
                        {log.details}
                        </p>
                    </div>
                    <div className="text-xs text-slate-400 dark:text-slate-500 whitespace-nowrap flex items-center gap-1">
                        <Clock size={12} />
                        {log.timestamp}
                    </div>
                </div>
                ))}
            </div>
            )}
        </div>
      )}
    </div>
  );
};

export default ManageUsers;

payload.text:
I have updated the `firestore.rules` file to be more robust. The `isAdmin` helper function now includes a check for the specific super-admin email (`infotech.peadato@gmail.com`) as a fallback, ensuring that even if the database record is missing or incorrect, the main admin can still access the data. I have also updated `ManageUsers.tsx` to display this improved configuration in the "Configuration Required" error message.

**Steps to resolve:**
1.  Go to the [Firebase Console](https://console.firebase.google.com/).
2.  Navigate to **Firestore Database** > **Rules**.
3.  Copy the rules below (or from the app's error screen) and paste them into the editor.
4.  Click **Publish**.

```javascript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to check if user is admin
    // Checks DB role OR hardcoded super-admin email as failsafe
    function isAdmin() {
      return (exists(/databases/$(database)/documents/users/$(request.auth.uid)) && 
              get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'Admin') ||
             request.auth.token.email == 'infotech.peadato@gmail.com';
    }

    // User profiles
    match /users/{userId} {
      allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());

      match /documents/{docId} {
        allow read, write: if request.auth != null && (request.auth.uid == userId || isAdmin());
      }
    }

    // Top-level concerns collection
    match /concerns/{concernId} {
      allow create: if request.auth != null;
      // Admins read all, Users read their own
      allow read: if request.auth != null && (resource.data.employeeId == request.auth.uid || isAdmin());
      // Admins can update (resolve)
      allow update: if request.auth != null && isAdmin();
    }

    // Audit logs
    match /audit_logs/{logId} {
      allow read: if request.auth != null && isAdmin();
      allow create: if request.auth != null;
    }
  }
}
```

This should immediately resolve the "Missing or insufficient permissions" error for the Admin when loading concerns.

