import React, { useEffect, useState, useMemo } from 'react';
import { PayrollDocument, DocStatus, ViewState, User, UserRole } from '../types';
import { CURRENCY_SYMBOL } from '../constants';
import StatsCard from '../components/StatsCard';
import { FileText, Users, Calendar, DollarSign, Eye, AlertTriangle, PieChart as PieChartIcon, BarChart3, Download } from 'lucide-react';
import { db } from '../utils/firebase';
import { collection, getDocs, query, getCountFromServer, collectionGroup } from 'firebase/firestore';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell, 
  Legend 
} from 'recharts';

interface DashboardProps {
  onNavigate: (view: ViewState) => void;
  currentUser: User;
}

const Dashboard: React.FC<DashboardProps> = ({ onNavigate, currentUser }) => {
  const [documents, setDocuments] = useState<PayrollDocument[]>([]);
  const [employeesCount, setEmployeesCount] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
        setIsLoading(true);
        setPermissionError(false);

        // 1. Fetch Documents
        try {
            let q;

            if (currentUser.role === UserRole.ADMIN) {
                // Admin: Fetch ALL documents across the entire database using Collection Group Query
                // This allows calculating total earnings for the whole company
                q = query(collectionGroup(db, 'documents'));
            } else {
                // Employee: Fetch only their specific documents
                q = query(collection(db, 'users', currentUser.id, 'documents'));
            }

            const querySnapshot = await getDocs(q);
            const loadedDocs: PayrollDocument[] = [];
            querySnapshot.forEach((doc) => {
                const data = doc.data();
                loadedDocs.push({
                    id: doc.id,
                    title: data.title,
                    company: data.company,
                    employeeId: data.employeeId,
                    employeeName: data.employeeName,
                    employeeEmail: data.employeeEmail,
                    uploadDate: data.uploadDate,
                    payrollPeriod: data.payrollPeriod,
                    amount: data.amount,
                    status: data.status as DocStatus,
                    type: data.type,
                    fileUrl: data.fileUrl,
                    storagePath: data.storagePath
                });
            });
            // Sort by uploadDate descending (client-side sort to be safe without compound indexes)
            loadedDocs.sort((a, b) => new Date(b.uploadDate).getTime() - new Date(a.uploadDate).getTime());
            setDocuments(loadedDocs);

        } catch (error: any) {
            console.error("Dashboard documents fetch failed:", error);
            if (error.code === 'permission-denied') {
                setPermissionError(true);
            }
        }

        // 2. Fetch Employees Count (Admin Only)
        if (currentUser.role === UserRole.ADMIN) {
            try {
                const usersRef = collection(db, 'users');
                const snapshot = await getCountFromServer(usersRef);
                setEmployeesCount(snapshot.data().count);
            } catch (error: any) {
                // Silently fail for stats if permissions don't allow global count
            }
        }

        setIsLoading(false);
    };

    fetchData();
  }, [currentUser]);

  // --- Data Processing for Charts ---

  const monthlyData = useMemo(() => {
    const grouped = documents.reduce((acc: any[], doc) => {
      // Parse date loosely assuming format like "Dec 01, 2025" or similar
      const date = new Date(doc.uploadDate);
      if (isNaN(date.getTime())) return acc;

      const monthYear = date.toLocaleString('default', { month: 'short', year: '2-digit' }); // e.g., "Dec 25"
      const sortKey = date.getFullYear() * 100 + date.getMonth();

      const existing = acc.find(item => item.name === monthYear);
      if (existing) {
        existing.amount += doc.amount;
        existing.count += 1;
      } else {
        acc.push({ name: monthYear, amount: doc.amount, count: 1, sortKey });
      }
      return acc;
    }, []);

    // Sort chronologically and take last 6 months
    return grouped.sort((a, b) => a.sortKey - b.sortKey).slice(-6);
  }, [documents]);

  const statusData = useMemo(() => {
    const counts = {
      [DocStatus.PENDING]: 0,
      [DocStatus.PROCESSED]: 0,
      [DocStatus.SENT]: 0
    };

    documents.forEach(doc => {
      if (counts[doc.status] !== undefined) {
        counts[doc.status]++;
      }
    });

    return [
      { name: 'Pending', value: counts[DocStatus.PENDING], color: '#f97316' }, // Orange-500
      { name: 'Processed', value: counts[DocStatus.PROCESSED], color: '#3b82f6' }, // Blue-500
      { name: 'Sent', value: counts[DocStatus.SENT], color: '#22c55e' } // Green-500
    ].filter(item => item.value > 0);
  }, [documents]);

  // --- Render ---

  const totalDocs = documents.length;
  const pendingDocs = documents.filter(d => d.status === DocStatus.PENDING).length;
  const totalPayroll = documents.reduce((acc, curr) => acc + curr.amount, 0);

  return (
    <div className="space-y-8 animate-in fade-in duration-300 pb-20">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900 dark:text-white">
            {currentUser.role === UserRole.ADMIN ? 'Admin Dashboard' : 'My Payroll Dashboard'}
          </h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1">
            {currentUser.role === UserRole.ADMIN ? 'Overview of all company payroll data' : 'Welcome back, view your latest payslips'}
          </p>
        </div>

        {currentUser.role === UserRole.ADMIN && (
            <button 
            onClick={() => onNavigate(ViewState.UPLOAD)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2.5 rounded-lg text-sm font-medium flex items-center gap-2 shadow-sm transition-colors w-full md:w-auto justify-center"
            >
            <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full hidden"></div>
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
            Upload Documents
            </button>
        )}
      </div>

      {permissionError && (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-xl p-4 flex items-start gap-3">
          <AlertTriangle className="text-red-600 dark:text-red-400 shrink-0 mt-0.5" size={20} />
          <div>
            <h3 className="text-sm font-bold text-red-900 dark:text-red-200">Database Access Denied</h3>
            <p className="text-sm text-red-700 dark:text-red-300 mt-1">
              <strong>Action Required:</strong> Your account does not have permission to read documents. 
              If you are an Admin, please update the Firestore Security Rules in your Firebase Console. See <code>README.md</code> for details.
            </p>
          </div>
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatsCard 
          label={currentUser.role === UserRole.ADMIN ? "Total Documents" : "My Documents"} 
          value={isLoading ? '-' : totalDocs} 
          icon={FileText} 
          colorClass="bg-blue-50 text-blue-900 dark:bg-blue-900/20 dark:text-blue-100" 
          iconBgClass="bg-blue-600 text-white dark:bg-blue-500"
        />
        {currentUser.role === UserRole.ADMIN && (
             <StatsCard 
             label="Employees" 
             value={isLoading ? '-' : employeesCount} 
             icon={Users} 
             colorClass="bg-green-50 text-green-900 dark:bg-green-900/20 dark:text-green-100" 
             iconBgClass="bg-green-600 text-white dark:bg-green-500"
           />
        )}

        <StatsCard 
          label="Pending" 
          value={isLoading ? '-' : pendingDocs} 
          icon={Calendar} 
          colorClass="bg-orange-50 text-orange-900 dark:bg-orange-900/20 dark:text-orange-100" 
          iconBgClass="bg-orange-600 text-white dark:bg-orange-500"
        />
        <StatsCard 
          label={currentUser.role === UserRole.ADMIN ? "Total Payout" : "Total Earned"}
          value={isLoading ? '-' : `${CURRENCY_SYMBOL}${totalPayroll.toLocaleString()}`} 
          icon={DollarSign} 
          colorClass="bg-purple-50 text-purple-900 dark:bg-purple-900/20 dark:text-purple-100" 
          iconBgClass="bg-purple-600 text-white dark:bg-purple-500"
        />
      </div>

      {/* Analytics Charts */}
      {!isLoading && documents.length > 0 && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

          {/* Bar Chart - Monthly Trends */}
          <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 p-6 transition-colors">
            <div className="flex items-center justify-between mb-6">
              <h3 className="font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <BarChart3 size={20} className="text-blue-600 dark:text-blue-400" />
                {currentUser.role === UserRole.ADMIN ? "Total Payroll Trends" : "Payroll History"}
              </h3>
            </div>
            <div className="h-64 w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={monthlyData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" className="dark:stroke-slate-700" />
                  <XAxis 
                    dataKey="name" 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: '#64748b', fontSize: 12 }} 
                    dy={10} 
                  />
                  <YAxis 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: '#64748b', fontSize: 12 }}
                  />
                  <Tooltip 
                    cursor={{ fill: 'transparent' }}
                    contentStyle={{ 
                      borderRadius: '12px', 
                      border: 'none', 
                      boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)',
                      backgroundColor: 'rgba(255, 255, 255, 0.95)'
                    }}
                    labelStyle={{ color: '#1e293b', fontWeight: 'bold' }}
                    formatter={(value: number) => [`${CURRENCY_SYMBOL}${value.toLocaleString()}`, 'Amount']}
                  />
                  <Bar 
                    dataKey="amount" 
                    fill="#3b82f6" 
                    radius={[4, 4, 0, 0]} 
                    barSize={32}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Pie Chart - Status Distribution */}
          <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 p-6 transition-colors">
            <div className="flex items-center justify-between mb-6">
              <h3 className="font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <PieChartIcon size={20} className="text-purple-600 dark:text-purple-400" />
                Document Status
              </h3>
            </div>
            <div className="h-64 w-full flex items-center justify-center">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={statusData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {statusData.map((entry, index) => (
