        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

          {/* Chart 1: Monthly Trends (Bar) */}
          <div className="bg-white dark:bg-slate-900 rounded-xl shadow-sm border border-slate-100 dark:border-slate-800 p-6 transition-colors flex flex-col">
